describe('updateCheckIntervalMinutes', () => {
  test('defaults to 30 when not set', () => {
    const config = parseConfigRecord({});
    expect(config.updateCheckIntervalMinutes).toBe(30);
  });
  test('accepts a valid positive integer', () => {
    const config = parseConfigRecord({ updateCheckIntervalMinutes: 60 });
    expect(config.updateCheckIntervalMinutes).toBe(60);
  });
  test('accepts 0 to disable periodic checks', () => {
    const config = parseConfigRecord({ updateCheckIntervalMinutes: 0 });
    expect(config.updateCheckIntervalMinutes).toBe(0);
  });
  test('falls back to 30 for negative numbers', () => {
    const config = parseConfigRecord({ updateCheckIntervalMinutes: -5 });
    expect(config.updateCheckIntervalMinutes).toBe(30);
  });
  test('falls back to 30 for non-integer values', () => {
    const config = parseConfigRecord({ updateCheckIntervalMinutes: 10.5 });
    expect(config.updateCheckIntervalMinutes).toBe(30);
  });
  test('falls back to 30 for non-number values', () => {
    const config = parseConfigRecord({ updateCheckIntervalMinutes: 'fast' });
    expect(config.updateCheckIntervalMinutes).toBe(30);
  });
});
```

